import React from 'react'

export default function Login(props) {

    let checkname = (event)=>{
        let name = event.target.value
        setName(name)
        if (name=="")
        setErrM("name is too short")
        else
        setErrM("")

    }
  return (
    <div>
        <h1>Welcome to our game!</h1>
        <file >
            <input type="text" onChange={props.saveName} placeholder='Please enter your name'/>
            <br></br>
            <button onClick="">Submit</button>
        </file>

    </div>
  )
}
